protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's indexing policy,
    // not EF Core. In EF Core 9 this call throws InvalidOperationException.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing documents and direct SQL queries
        // (e.g. WHERE c.Discriminator = 'Product') continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "EntityType|Key" to just "Key".
        // Preserve the old compound format so existing documents (e.g. "Product|123")
        // remain readable via FindAsync and point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

